  1→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
  2→import type { KeyboardEvent } from "react";
  3→import type { FileUIPart } from "ai";
  4→import type { SessionFileEntry } from "@/hooks/useSessions";
  5→
  6→const STOP_CHARS = /[\s,;:!?,()[\]{}<>"'`]/;
  7→const MENTION_TRIGGER_PREFIX = /\s|[([{]/;
  8→const LEADING_DOT_SLASH = /^\.\//;
  9→const NON_WHITESPACE_START = /^\S/;
 10→const MAX_WORKSPACE_FILES = 500;
 11→const MAX_DIRECTORY_SCANS = 200;
 12→
 13→type MentionRange = {
 14→  start: number;
 15→  end: number;
 16→  query: string;
 17→};
 18→
 19→type WorkspaceFile = {
 20→  path: string;
 21→  size?: number;
 22→};
 23→
 24→export type MentionOptionBase = {
 25→  id: string;
 26→  type: "attachment" | "workspace";
 27→  label: string;
 28→  description?: string;
 29→  insertValue: string;
 30→  meta?: {
 31→    path?: string;
 32→    size?: number;
 33→    mediaType?: string;
 34→  };
 35→};
 36→
 37→export type MentionOption = MentionOptionBase & {
 38→  order: number;
 39→};
 40→
 41→export type MentionSections = {
 42→  attachments: MentionOption[];
 43→  workspace: MentionOption[];
 44→};
 45→
 46→type UseFileMentionsArgs = {
 47→  text: string;
 48→  setText: (value: string) => void;
 49→  textareaRef: React.RefObject<HTMLTextAreaElement | null>;
 50→  attachments: (FileUIPart & { id: string })[];
 51→  sessionId?: string;
 52→  listDirectory?: (
 53→    sessionId: string,
 54→    path?: string,
 55→  ) => Promise<SessionFileEntry[]>;
 56→};
 57→
 58→type UseFileMentionsReturn = {
 59→  isOpen: boolean;
 60→  query: string;
 61→  flatOptions: MentionOption[];
 62→  sections: MentionSections;
 63→  activeIndex: number;
 64→  setActiveIndex: (value: number) => void;
 65→  handleTextChange: (value: string, caret: number | null) => void;
 66→  handleCaretChange: (caret: number | null) => void;
 67→  handleKeyDown: (event: KeyboardEvent<HTMLTextAreaElement>) => void;
 68→  selectOption: (option?: MentionOption) => void;
 69→  closeMenu: () => void;
 70→  workspaceStatus: "idle" | "loading" | "ready" | "error";
 71→  workspaceError: string | null;
 72→  retryWorkspace: () => void;
 73→};
 74→
 75→const detectMention = (
 76→  text: string,
 77→  caret: number | null,
 78→): MentionRange | null => {
 79→  const safeCaret = Math.max(0, Math.min(text.length, caret ?? text.length));
 80→  const upToCaret = text.slice(0, safeCaret);
 81→  const triggerIndex = upToCaret.lastIndexOf("@");
 82→  if (triggerIndex === -1) {
 83→    return null;
 84→  }
 85→
 86→  if (triggerIndex > 0) {
 87→    const previousChar = upToCaret[triggerIndex - 1];
 88→    if (previousChar && !MENTION_TRIGGER_PREFIX.test(previousChar)) {
 89→      return null;
 90→    }
 91→  }
 92→
 93→  const query = upToCaret.slice(triggerIndex + 1);
 94→  if (STOP_CHARS.test(query)) {
 95→    return null;
 96→  }
 97→
 98→  return {
 99→    start: triggerIndex,
100→    end: safeCaret,
101→    query,
102→  };
103→};
104→
105→const isSameRange = (a: MentionRange | null, b: MentionRange | null): boolean =>
106→  a?.start === b?.start && a?.end === b?.end && a?.query === b?.query;
107→
108→const normalizePath = (value: string) => {
109→  if (value === "." || value === "./" || value === "") {
110→    return ".";
111→  }
112→  return value.replace(LEADING_DOT_SLASH, "");
113→};
114→
115→const crawlWorkspace = async ({
116→  sessionId,
117→  listDirectory,
118→}: {
119→  sessionId: string;
120→  listDirectory: UseFileMentionsArgs["listDirectory"];
121→}): Promise<WorkspaceFile[]> => {
122→  if (!listDirectory) {
123→    return [];
124→  }
125→
126→  const files: WorkspaceFile[] = [];
127→  const queue: string[] = ["."];
128→  const visited = new Set<string>();
129→
130→  while (
131→    queue.length > 0 &&
132→    files.length < MAX_WORKSPACE_FILES &&
133→    visited.size < MAX_DIRECTORY_SCANS
134→  ) {
135→    const current = queue.shift() as string;
136→    if (visited.has(current)) {
137→      continue;
138→    }
139→    visited.add(current);
140→
141→    // "." should be treated as undefined for API root
142→    const path = current === "." ? undefined : current;
143→    const entries = await listDirectory(sessionId, path);
144→
145→    for (const entry of entries) {
146→      const fullPath =
147→        current === "."
148→          ? entry.name
149→          : `${normalizePath(current)}/${entry.name}`;
150→      if (entry.type === "directory") {
151→        queue.push(fullPath);
152→        continue;
153→      }
154→      files.push({
155→        path: fullPath,
156→        size: entry.size,
157→      });
158→      if (files.length >= MAX_WORKSPACE_FILES) {
159→        break;
160→      }
161→    }
162→  }
163→
164→  return files;
165→};
166→
167→const toAttachmentOptions = (
168→  attachments: (FileUIPart & { id: string })[],
169→): MentionOptionBase[] =>
170→  attachments.map((attachment, index) => {
171→    const label =
172→      attachment.filename && attachment.filename.trim().length > 0
173→        ? attachment.filename
174→        : `Attachment ${index + 1}`;
175→    return {
176→      id: `upload-${attachment.id}`,
177→      type: "attachment" as const,
178→      label,
179→      description: attachment.mediaType ?? "Pending upload",
180→      insertValue: label,
181→      meta: {
182→        mediaType: attachment.mediaType,
183→      },
184→    };
185→  });
186→
187→const toWorkspaceOptions = (files: WorkspaceFile[]): MentionOptionBase[] =>
188→  files.map((file) => {
189→    const segments = file.path.split("/");
190→    const label = segments.at(-1) ?? file.path;
191→    return {
192→      id: `workspace-${file.path}`,
193→      type: "workspace" as const,
194→      label,
195→      description: file.path,
196→      insertValue: file.path,
197→      meta: {
198→        path: file.path,
199→        size: file.size,
200→      },
201→    };
202→  });
203→
204→const filterOptions = (
205→  options: MentionOptionBase[],
206→  query: string,
207→  offset: number,
208→): MentionOption[] => {
209→  if (!options.length) {
210→    return [];
211→  }
212→  const normalizedQuery = query.trim().toLowerCase();
213→  const matchesQuery = (value?: string) =>
214→    normalizedQuery.length === 0
215→      ? true
216→      : value?.toLowerCase().includes(normalizedQuery);
217→
218→  return options
219→    .filter(
220→      (option) =>
221→        matchesQuery(option.insertValue) ||
222→        matchesQuery(option.label) ||
223→        matchesQuery(option.description),
224→    )
225→    .map((option, index) => ({
226→      ...option,
227→      order: offset + index,
228→    }));
229→};
